CREATE TABLE IF NOT EXISTS sup_asn_transport_fact (
 transport_fact_id bigint NOT NULL AUTO_INCREMENT,asn_id bigint NOT NULL,shipment_id bigint NULL,waybill_no varchar(64) NULL,carrier_code varchar(64) NULL,transport_status smallint NOT NULL COMMENT '1待发运 2运输中 3已到达 4异常',last_node varchar(256) NULL,last_track_at datetime(3) NULL,exception_code varchar(64) NULL,exception_reason varchar(512) NULL,source_version bigint NOT NULL DEFAULT 0,created_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),updated_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),PRIMARY KEY(transport_fact_id),UNIQUE KEY uk_sup_asn_transport(asn_id),KEY idx_sup_transport_waybill(waybill_no,transport_status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='ASN运输事实快照';
